const now = new Date();
const today = now.toISOString().slice(0, 10);
const due = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
const runId = `N8N-STOCK-E2E-EXC-${Date.now()}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, dueDate: due, customerName: `${runId} KH vòng đời ngoại lệ`, itemGroup: `${runId} Nhóm ngoại lệ sau bán`, sellWarehouseName: `${runId} Kho bán`, warrantyWarehouseName: `${runId} Kho bảo hành`, defectWarehouseName: `${runId} Kho hàng lỗi`, repairWarehouseName: `${runId} Kho xưởng ảo`, itemCode: `${runId} Hàng bán lỗi đổi trả`, receiptQty: 5, saleQty: 2, returnQty: 1, rate: 91, accounts: { receivable: '1310 - Debtors - TDD', sales: '4110 - Sales - TDD' } } }];

const ctx = $('Build E2E Exception Context').first().json;
const bins = $('Verify Return Bins').all().map(i => i.json);
const sleRows = $('Verify Return SLE').all().map(i => i.json);
const invoice = $('Submit Stock Sales Invoice').first().json;
const creditNote = $('Submit Return Credit Note').first().json;
const saleWh = $('Create Sellable Warehouse').first().json.name;
const warrantyWh = $('Create Warranty Warehouse').first().json.name;
const defectWh = $('Create Defect Warehouse').first().json.name;
const repairWh = $('Create Repair Warehouse').first().json.name;
const byWarehouse = Object.fromEntries(bins.map(row => [row.warehouse, Number(row.actual_qty)]));
const saleRows = sleRows.filter(row => row.voucher_no === $('Create Stock Sales Invoice').first().json.name);
const returnRows = sleRows.filter(row => row.voucher_no === $('Create Return Credit Note').first().json.name);
const status = Number(invoice.docstatus) === 1 && Number(creditNote.docstatus) === 1 && byWarehouse[saleWh] === ctx.receiptQty - ctx.saleQty && (byWarehouse[warrantyWh] ?? 0) === 0 && (byWarehouse[defectWh] ?? 0) === 0 && (byWarehouse[repairWh] ?? 0) === 0 && saleRows.some(row => Number(row.actual_qty) === -ctx.saleQty) && returnRows.some(row => Number(row.actual_qty) === ctx.returnQty);
const text = JSON.stringify({ bins, sleRows, invoice: { name: invoice.name, docstatus: invoice.docstatus }, creditNote: { name: creditNote.name, docstatus: creditNote.docstatus, return_against: creditNote.return_against } });
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
return [{ json: { status: status && securityFindings.length === 0 ? 'passed' : 'failed', runId: ctx.runId, item: $('Create Return Item').first().json.name, customer: $('Create Return Customer').first().json.name, salesInvoice: invoice.name, salesInvoiceDocstatus: invoice.docstatus, creditNote: creditNote.name, creditNoteDocstatus: creditNote.docstatus, creditNoteReturnAgainst: creditNote.return_against, sellableWarehouse: saleWh, warrantyWarehouse: warrantyWh, defectWarehouse: defectWh, repairWarehouse: repairWh, sellableQtyFinal: byWarehouse[saleWh], warrantyQtyFinal: byWarehouse[warrantyWh] ?? 0, defectQtyFinal: byWarehouse[defectWh] ?? 0, repairQtyFinal: byWarehouse[repairWh] ?? 0, stockEntries: { receipt: $('Create Retail Receipt').first().json.name, warrantyToDefect: $('Create Warranty To Defect Transfer').first().json.name, defectToRepair: $('Create Defect To Repair Transfer').first().json.name, disposalIssue: $('Create Repair Disposal Issue').first().json.name }, ledgerRows: sleRows.length, saleLedgerActualQty: saleRows.map(row => row.actual_qty), returnLedgerActualQty: returnRows.map(row => row.actual_qty), securityFindings } }];
